<template>
    <div>
        <Header title="问卷详情" v-if="!ifWx" />
        <div class="mainBox" v-if="questionData">
            <SubHeader :subTitle="questionData.name"/>
            <div class="desc">
                {{questionData.describe}}
            </div>
            <van-form class="main" validate-first>
                <ul>
                    <template v-for="(item,index) in questionData.questions" :key="item.id">
                        <li >
                            <div class="sub_title">
                                {{index+1}} {{item.name}}
                            </div>
                            <div v-if="item.type == 1">
                                <van-radio-group v-model="item.answer">
                                    <van-radio :name="subItem.id" v-for="subItem in item.items" :key="subItem.id">{{subItem.name}}</van-radio>
                                </van-radio-group>
                            </div>
                            <div v-else-if="item.type == 2">
                                <van-checkbox-group v-model="item.answer">
                                    <van-checkbox :name="subItem.id" v-for="subItem in item.items" :key="subItem.id" shape="square">{{subItem.name}}</van-checkbox>
                                </van-checkbox-group>
                            </div>
                            <div v-else-if="item.type == 3">
                                <van-field
                                        v-model="item.answer"
                                        border
                                        rows="1"
                                        autosize
                                        type="textarea"
                                        label=""
                                        placeholder="请输入"
                                        style="border: 1px solid #EAEEF2;"
                                        :rules="[
                                    { required: true, message: '请填写答题内容' }
                                ]"
                                />
                            </div>
                            <div v-else-if="item.type == 4">
                                <van-rate v-model="state.answer" gutter="25px" color="#FFCE70"/>
                            </div>
                            <div v-else-if="item.type == 5">
                                <van-uploader
                                        v-model="state.answer"
                                        :after-read="afterRead"
                                        multiple
                                        :preview-full-image="false"
                                        :max-count="10"
                                        accept="*"
                                        :max-size="10* 1024 * 1024"
                                        @oversize="onOversize">
                                    <van-button icon="plus"></van-button>
                                    <template #preview-cover="{ file }">
                                        <div class="preview-cover van-ellipsis">{{ file?file.name:''}}</div>
                                    </template>
                                </van-uploader>
                            </div>
                            <div v-else-if="item.type == 6">
                                <van-field
                                        v-model="originNameObj[item.id]"
                                        is-link
                                        readonly
                                        label="医院"
                                        placeholder="请选择医院"
                                        @click="openSearch(item)"
                                />
                            </div>
                            <div v-else-if="item.type == 7">
                                <van-field
                                        v-model="originNameObj[item.id]"
                                        is-link
                                        readonly
                                        label="科室"
                                        placeholder="请选择科室"
                                        @click="openSearch(item)"
                                />
                            </div>
                        </li>
                    </template>
                    <li>
                    <div class="sub_title">
                        1 单选题？
                    </div>
                    <div>
                        <van-radio-group v-model="state.radio">
                            <van-radio name="1">单选框 1</van-radio>
                            <van-radio name="2">单选框 2</van-radio>
                        </van-radio-group>
                    </div>
                    </li>

                    <li>
                        <div class="sub_title">
                            2 多选题
                        </div>
                        <div>
                            <van-checkbox-group v-model="state.checkbox">
                                <van-checkbox name="a" shape="square">复选框 a</van-checkbox>
                                <van-checkbox name="b" shape="square">复选框 b</van-checkbox>
                                <van-checkbox name="c" shape="square">复选框 c</van-checkbox>
                            </van-checkbox-group>
                        </div>
                    </li>

                    <li>
                        <div class="sub_title">
                            3 填空题
                        </div>
                        <div>
                            <van-field
                                    v-model="state.field"
                                    border
                                    rows="1"
                                    autosize
                                    type="textarea"
                                    label=""
                                    placeholder="请输入"
                                    style="border: 1px solid #EAEEF2;"
                                    :rules="[
                                    { required: true, message: '请填写答题内容' }
                                ]"
                            />
                        </div>
                    </li>
                    <li>
                        <div class="sub_title">
                            4 打分题
                        </div>
                        <div>
                            <van-rate v-model="state.rate" gutter="25px" color="#FFCE70"/>
                        </div>
                    </li>
                    <li>
                        <div class="sub_title">
                            5 文件上传题 <span>最多可上传10个</span>
                        </div>
                        <div>
                            <van-uploader
                                    v-model="state.fileList"
                                    :after-read="afterRead"
                                    multiple
                                    :preview-full-image="false"
                                    :max-count="10"
                                    accept="*"
                                    :max-size="10* 1024 * 1024"
                                    @oversize="onOversize">
                                <van-button icon="plus"></van-button>
                                <template #preview-cover="{ file }">
                                    <div class="preview-cover van-ellipsis">{{ file?file.name:''}}</div>
                                </template>
                            </van-uploader>
                        </div>
                    </li>
                </ul>
                <div class="submitBtn">
                    <van-button block type="primary" @click="onSubmit">提交</van-button>
                </div>
            </van-form>
        </div>
    </div>
</template>

<script>
import Header from '@/components/Header'
import SubHeader from '@/components/SubHeader'
import { reactive, nextTick } from 'vue'
import { mapState } from 'vuex'
import { Toast } from 'vant'
import useIfWx from '../../mixin/useIfWx'
export default {
    name: 'Questionnaire',
    components: {
        Header, SubHeader
    },
    setup() {
        const { ifWx } = useIfWx()
        const state = reactive({
            field: null,
            radio: null,
            rate: null,
            checkbox: [],
            fileList: [
                // {
                //     url: 'https://img.yzcdn.cn/vant/leaf.jpg',
                //     status: 'uploading',
                //     message: '上传中...',
                // },
                // {
                //     url: 'https://img.yzcdn.cn/vant/tree.jpg',
                //     status: 'failed',
                //     message: '上传失败',
                // },
                {
                    url: 'https://img.yzcdn.cn/vant/leaf.jpg',
                    status: 'done',
                    message: '上传成功...'
                }
            ]
        })
        const srtFileSrc = (type) => {
            nextTick(() => {
                const previews = document.querySelectorAll('.van-uploader__preview')
                const preview = previews[previews.length - 1].querySelector('.van-uploader__preview-image')
                var img = document.createElement('img')
                img.src = `./static/img/${type}.png`
                preview.replaceChild(img, preview.childNodes[0])
            })
        }
        // 文件读取完成后的回调函数
        const afterRead = (res) => {
            const fileName = res.file.name
            let last = state.fileList[state.fileList.length - 1]
            last = Object.assign(last, {
                isImage: true,
                status: 'uploading',
                message: '上传中'
            })
            if (!/\.(gif|jpg|jpeg|png|GIF|JPG|PNG)$/i.test(fileName)) {
                if (/\.(xls|xlsx|csv)$/i.test(fileName)) {
                    srtFileSrc('excel')
                } else if (/\.(doc|docx)$/i.test(fileName)) {
                    srtFileSrc('word')
                } else if (/\.(ppt|pptx)$/i.test(fileName)) {
                    srtFileSrc('ppt')
                } else if (/\.(pdf)$/i.test(fileName)) {
                    srtFileSrc('pdf')
                } else if (/\.(mp4|m2v|mkv|rmvb|wmv|avi|flv|mov|m4v)$/i.test(fileName)) {
                    srtFileSrc('video')
                } else if (/\.(mp3|wav|wmv)$/i.test(fileName)) {
                    srtFileSrc('radio')
                } else {
                    srtFileSrc('other')
                }
            }
            setTimeout(() => {
                last['status'] = 'done'
                last['message'] = '上传成功'
                last['url'] = 'https://img.yzcdn.cn/vant/tree.jpg'
            }, 2000)
        }
        const onOversize = () => {
            Toast('文件大小不能超过 10M')
        }
        return {
            ifWx,
            state,
            afterRead,
            onOversize
        }
    },
    data() {
        return {
            name: null,
            describe: null,
            questionData: null
        }
    },
    mounted() {
        this.getData()
    },
    computed: {
        ...mapState({
            QuestionCellphone: state => state.QuestionCellphone,
            originNameObj: state => state.questionSearch.originNameObj
        })
    },
    methods: {
        // 获取问卷详情
        async getData() {
            const res = await this.Ajax('getQuestionDetail', 'post', null, {
                mobile: this.QuestionCellphone,
                token: this.$route.query.token
            })
            const { questions } = res.data
            const arr = questions.map(item => {
                if (/[13467]/.test(item.type)) {
                    item['answer'] = ''
                } else if (/[25]/.test(item.type)) {
                    item['answer'] = []
                }
                return item
            })
            res.data['questions'] = arr
            this.questionData = res.data
        },
        async  onSubmit() {
            const { questions } = this.questionData
            for (const item of questions) {
                if (/[67]/.test(item.type)) {
                    item['answer'] = this.originNameObj[item.id]
                }
            }
            console.log(questions)
            // const res = await this.Ajax('submitQuestionDetail', 'post', null, {
            //     mobile: this.QuestionCellphone,
            //     id: this.questionData.id,
            //     isPreview: false,
            //     userInfo: {}
            // })
            // this.questionData = res.data
        },
        openSearch(item) {
            this.$router.push({
                name: 'search',
                params: item
            })
        }
    }
}
</script>

